import boto3
import json
import os

class SQSMessagePublisher:
    def __init__(self, queue_url: str, region_name: str = None):
        self.queue_url = queue_url
        if region_name:
            self.sqs_client = boto3.client('sqs', region_name=region_name)
        else:
            self.sqs_client = boto3.client('sqs')

    def publish_message(self, user_data: dict, message_group_id: str = None, message_deduplication_id: str = None) -> dict:
        message_body = json.dumps(user_data)

        try:
            send_params = {
                'QueueUrl': self.queue_url,
                'MessageBody': message_body
            }

            if message_group_id:
                send_params['MessageGroupId'] = message_group_id
            if message_deduplication_id:
                send_params['MessageDeduplicationId'] = message_deduplication_id

            response = self.sqs_client.send_message(**send_params)
            return response
        except Exception as e:
            raise

